package main
import "fmt"

type bota struct{
    tam int
    pe string
}

func criarvetor(qtd int) []bota {
    vetor := make([]bota,qtd)
    for i := 0; i < len(vetor); i++ {
        fmt.Scan(&vetor[i])
    }
    return vetor
}


func main() {
     qtd := 0
     fmt.Scan(&qtd)
     vetor := criarvetor(qtd)


    fmt.Println(vetor)
}
